import React, { useState, useEffect } from 'react';
import './styles/App.css';
import Terminal from './functions/Terminal';
import Box from './functions/Box';
import ResumeContent from './functions/ResumeContent';
import ReactGithubList from './ReactGithubList/react-github-widget';

const App = () => {
  const [activeApp, setActiveApp] = useState(null);

  useEffect(() => {

  }, []);

  const handleBoxClick = (boxName) => {
    setActiveApp(boxName);
  };

  const box1Text = activeApp === 'box1' ? 'Scroll Down!' : 'About Me';
  const box2Text = activeApp === 'box2' ? 'Scroll Down!' : 'Projects';
  const box3Text = activeApp === 'box3' ? 'Scroll Down!' : 'Resume';
  let content = null;

  if (activeApp === 'box3') {
    content = <ResumeContent />;
  } else if (activeApp === 'box2') {
    content = <ReactGithubList username="qNateYT" />;
  }

  const handleCodeTerminalClick = (languageIndex) => {
    setActiveApp(`codeTerminal${languageIndex}`);
  };

  const renderCodeTerminals = () => {
    const languages = ['HTML', 'CSS', 'PHP', 'Python', 'Java', 'JavaScript', 'React.js', 'Ruby', 'Perl', 'Node.js', 'C++', 'C#'];

    return languages.map((language, index) => (
      <div
        className={`terminal ${activeApp === `codeTerminal${index}` ? 'active' : ''}`}
        onClick={() => handleCodeTerminalClick(index)}
        key={index}
      >
        <pre className="terminal-line">
          <code>{`// ${language} code snippet`}</code>
        </pre>
        <pre className="terminal-line">
          <code>{`// Write your ${language} code here`}</code>
        </pre>
      </div>
    ));
  };

  return (
    <div className="App">
      <header className="App-header">
        <div className="terminal-container">
          {renderCodeTerminals()}
        </div>
        <div className="box-container">
          <Box
            active={activeApp === 'box1'}
            boxText={box1Text}
            onClick={() => handleBoxClick('box1')}
          >
            {activeApp !== 'box1' && 'My Backstory'}
          </Box>
          <Box
            active={activeApp === 'box2'}
            boxText={box2Text}
            onClick={() => handleBoxClick('box2')}
          >
            {activeApp !== 'box2' && 'Past, Current, and Future Projects'}
          </Box>
          <Box
            active={activeApp === 'box3'}
            boxText={box3Text}
            onClick={() => handleBoxClick('box3')}
          >
            {activeApp !== 'box3' && 'My Resume'}
          </Box>
        </div>
        {activeApp && activeApp.startsWith('codeTerminal') && (
          <div className="text-container">
            <h3>{`Editing ${activeApp.slice(12)} code`}</h3>
            <pre className="terminal-line">
              <code>{`// Write your ${activeApp.slice(12)} code here`}</code>
            </pre>
          </div>
        )}
        {activeApp && !activeApp.startsWith('codeTerminal') && (
          <div className="text-container">
            {content}
          </div>
        )}
      </header>
    </div>
  );
};

export default App;
